import React from 'react';
import { useTheme } from '../../context/ThemeContext';
import { SunIcon, MoonIcon } from '@heroicons/react/24/outline';

const ThemeToggle = () => {
  const { darkMode, toggleTheme } = useTheme();

  return (
    <button
      onClick={toggleTheme}
      className="relative inline-flex h-8 w-14 items-center rounded-full transition-colors duration-300 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:ring-offset-2"
      style={{
        backgroundColor: darkMode ? '#4f46e5' : '#e2e8f0'
      }}
      aria-label="Toggle theme"
    >
      <span
        className={`inline-flex h-6 w-6 transform items-center justify-center rounded-full bg-white shadow-lg transition-transform duration-300 ${
          darkMode ? 'translate-x-7' : 'translate-x-1'
        }`}
      >
        {darkMode ? (
          <MoonIcon className="h-3.5 w-3.5 text-indigo-600" />
        ) : (
          <SunIcon className="h-3.5 w-3.5 text-yellow-500" />
        )}
      </span>
    </button>
  );
};

export default ThemeToggle;
